{
  "candidate_id": "ko_identity_candidate_004",
  "unordered_mentions": [
    {
      "mention_id": "ko_mention_holdout_023",
      "lecture_id": "numerical_root_finding_001",
      "name": "Damped Newton method",
      "type": "Method",
      "upstream_source_spans": [
        "The damped Newton method extends Newton's method by scaling the Newton correction with a factor between zero and one."
      ]
    },
    {
      "mention_id": "ko_mention_holdout_035",
      "lecture_id": "statistics_estimation_001",
      "name": "Newton's Method",
      "type": "Method",
      "upstream_source_spans": [
        "Newton's method can be applied within maximum likelihood estimation to compute a candidate numerically."
      ]
    }
  ],
  "evidence_catalog": [
    {
      "evidence_id": "evidence_001",
      "lecture_id": "numerical_root_finding_001",
      "span": "A root-finding problem asks for a value \\(x^*\\) at which a scalar function is zero:"
    },
    {
      "evidence_id": "evidence_002",
      "lecture_id": "numerical_root_finding_001",
      "span": "\\[\nf(x^*) = 0.\n\\]"
    },
    {
      "evidence_id": "evidence_003",
      "lecture_id": "numerical_root_finding_001",
      "span": "Newton's method uses the derivative to replace the function locally by its tangent line. Provided \\(f'(x_k)\\neq 0\\), its update is"
    },
    {
      "evidence_id": "evidence_004",
      "lecture_id": "numerical_root_finding_001",
      "span": "\\[\nx_{k+1} = x_k - \\frac{f(x_k)}{f'(x_k)}.\n\\]"
    },
    {
      "evidence_id": "evidence_005",
      "lecture_id": "numerical_root_finding_001",
      "span": "The damped Newton method extends Newton's method by scaling the Newton correction with a factor between zero and one. This extra control can prevent a full Newton step from moving too far when the current iterate is not yet near a root."
    },
    {
      "evidence_id": "evidence_006",
      "lecture_id": "numerical_root_finding_001",
      "span": "The bisection method begins with a sign-changing bracket \\([a,b]\\) satisfying \\(f(a)f(b)<0\\). It evaluates the midpoint"
    },
    {
      "evidence_id": "evidence_007",
      "lecture_id": "numerical_root_finding_001",
      "span": "\\[\nm = \\frac{a+b}{2}\n\\]"
    },
    {
      "evidence_id": "evidence_008",
      "lecture_id": "numerical_root_finding_001",
      "span": "and retains the half-interval whose endpoints still have opposite signs."
    },
    {
      "evidence_id": "evidence_009",
      "lecture_id": "numerical_root_finding_001",
      "span": "Newton's method and the bisection method contrast in the information they use: Newton's method requires derivative values and can converge rapidly near a root, whereas bisection uses only function signs and preserves a bracket at every iteration."
    },
    {
      "evidence_id": "evidence_010",
      "lecture_id": "statistics_estimation_001",
      "span": "A statistical model is a family of probability distributions indexed by an unknown parameter \\(\\theta\\). The likelihood is defined from this statistical model by treating the observations as fixed and comparing possible parameter values. For independent observations \\(x_1,\\ldots,x_n\\), it is"
    },
    {
      "evidence_id": "evidence_011",
      "lecture_id": "statistics_estimation_001",
      "span": "\\[\nL(\\theta; x_{1:n}) = \\prod_{i=1}^{n} p(x_i \\mid \\theta).\n\\]"
    },
    {
      "evidence_id": "evidence_012",
      "lecture_id": "statistics_estimation_001",
      "span": "The log-likelihood is obtained by taking the logarithm of the likelihood. Independence turns the product into a sum:"
    },
    {
      "evidence_id": "evidence_013",
      "lecture_id": "statistics_estimation_001",
      "span": "\\[\n\\ell(\\theta) = \\log L(\\theta; x_{1:n}) = \\sum_{i=1}^{n} \\log p(x_i \\mid \\theta).\n\\]"
    },
    {
      "evidence_id": "evidence_014",
      "lecture_id": "statistics_estimation_001",
      "span": "Maximum likelihood estimation uses the log-likelihood as its objective and selects a parameter value that maximizes it:"
    },
    {
      "evidence_id": "evidence_015",
      "lecture_id": "statistics_estimation_001",
      "span": "\\[\n\\widehat{\\theta}_{\\mathrm{MLE}} = \\operatorname*{arg\\,max}_{\\theta}\\, \\ell(\\theta).\n\\]"
    },
    {
      "evidence_id": "evidence_016",
      "lecture_id": "statistics_estimation_001",
      "span": "The score function is the derivative of the log-likelihood with respect to the parameter,"
    },
    {
      "evidence_id": "evidence_017",
      "lecture_id": "statistics_estimation_001",
      "span": "\\[\ns(\\theta) = \\nabla_{\\theta}\\ell(\\theta).\n\\]"
    },
    {
      "evidence_id": "evidence_018",
      "lecture_id": "statistics_estimation_001",
      "span": "At an interior differentiable optimum, an MLE candidate satisfies the score equation \\(s(\\theta)=0\\). When this equation has no closed-form solution, Newton's method can be applied within maximum likelihood estimation to compute a candidate numerically."
    }
  ]
}
